import { memo, useState, useEffect, useRef, useCallback } from "react";
import { cn } from "@/lib/utils";
import { MessageCircle, Search, ChefHat, BookOpen, Store, ThumbsUp, ThumbsDown, Camera } from "lucide-react";
import { useStoryReactions } from "@/hooks/useStoryReactions";
import { isIOSDevice } from "@/lib/externalLinks";
import type { HomepageTemplate } from "@/hooks/useHomepageTemplates";

const sushiRamenHero = "/images/sushi-ramen-hero.jpg";

const countryFlagCodes: Record<string, string> = {
  Portugal: "pt", China: "cn", Japan: "jp", Korea: "kr", "South Korea": "kr",
  Spain: "es", France: "fr", Germany: "de", Italy: "it",
  "United Kingdom": "gb", "United States": "us", USA: "us",
  Brazil: "br", Netherlands: "nl", Belgium: "be",
};
const sushiRamenMobile = "/images/sushi-ramen-mobile.jpg";

// Hook to determine if we should use lightweight mode for better performance
const useLightweightMode = (): boolean => {
  const getWindowWidth = () => {
    try { return typeof window !== 'undefined' ? window.innerWidth : 1024; } catch { return 1024; }
  };
  const getConnection = () => {
    try { return typeof navigator !== 'undefined' ? (navigator as any).connection : null; } catch { return null; }
  };
  const getDeviceMemory = () => {
    try { return typeof navigator !== 'undefined' ? (navigator as any).deviceMemory : null; } catch { return null; }
  };

  const windowWidth = getWindowWidth();
  const isMobile = windowWidth < 640;
  const isDesktop = windowWidth >= 1024;
  const connection = getConnection();

  let isCapacitor = false;
  let isWebView = false;
  try {
    const { isCapacitorApp, isInWebView } = require("@/lib/externalLinks");
    isCapacitor = isCapacitorApp();
    isWebView = isInWebView();
  } catch {}

  if (isDesktop) {
    if (connection?.saveData) return true;
    return false;
  }
  if (isWebView && !isCapacitor) return true;
  if (connection) {
    if (connection.saveData) return true;
    if (connection.effectiveType === '2g' || connection.effectiveType === 'slow-2g') return true;
  }
  const deviceMemory = getDeviceMemory();
  if (isMobile && deviceMemory && deviceMemory < 2) return true;
  return false;
};

// Hero reaction counts shown next to breathing light
const HeroReactionCounts = ({ templateId }: { templateId: string }) => {
  const { counts } = useStoryReactions(templateId, "template");
  if (counts.likes === 0 && counts.dislikes === 0) return null;
  return (
    <span className="flex items-center gap-1.5 text-[11px] text-white/60 drop-shadow-md ml-1">
      {counts.likes > 0 && (
        <span className="flex items-center gap-0.5">
          <ThumbsUp className="w-3 h-3" />
          {counts.likes}
        </span>
      )}
      {counts.dislikes > 0 && (
        <span className="flex items-center gap-0.5">
          <ThumbsDown className="w-3 h-3" />
          {counts.dislikes}
        </span>
      )}
    </span>
  );
};

const getDeviceType = () => {
  try {
    if (typeof window === 'undefined') return 'desktop';
    const width = window.innerWidth;
    if (width < 640) return 'mobile';
    if (width < 1024) return 'tablet';
    return 'desktop';
  } catch { return 'desktop'; }
};

// Hero Slide Component
const HeroSlide = memo(({ 
  template, isActive, currentLang, t,
  onContentReady, onAskXiaoxiong, onDIYCook, onPhotoStory, onClaimStore
}: { 
  template: HomepageTemplate; 
  isActive: boolean;
  currentLang: string;
  t: any;
  onContentReady?: () => void;
  onAskXiaoxiong?: () => void;
  onDIYCook?: () => void;
  onPhotoStory?: (storyText: string, templateId: string, restaurantId?: string | null) => void;
  onClaimStore?: () => void;
}) => {
  const [postersLoaded, setPostersLoaded] = useState<Record<string, boolean>>({});
  const [videosReady, setVideosReady] = useState<Record<string, boolean>>({});
  const [videoErrors, setVideoErrors] = useState<Record<string, boolean>>({});
  const [imagesLoaded, setImagesLoaded] = useState<Record<string, boolean>>({ mobile: true, tablet: true, desktop: true });
  const [shouldLoadVideo, setShouldLoadVideo] = useState(false);
  const isLightweight = useLightweightMode();

  const mobileVideoRef = useRef<HTMLVideoElement>(null);
  const tabletVideoRef = useRef<HTMLVideoElement>(null);
  const desktopVideoRef = useRef<HTMLVideoElement>(null);

  const getLocalizedText = (field: string) => {
    const langSuffix = currentLang === "zh" ? "_zh" : currentLang === "pt" ? "_pt" : currentLang === "en" ? "_en" : null;
    if (!langSuffix) return "";
    return (template as any)[`${field}${langSuffix}`] || "";
  };

  const getOverlayOpacity = () => {
    const deviceType = getDeviceType();
    if (deviceType === 'mobile' && template.mobile_overlay_opacity !== null) return template.mobile_overlay_opacity;
    if (deviceType === 'tablet' && template.tablet_overlay_opacity !== null) return template.tablet_overlay_opacity;
    if (deviceType === 'desktop' && template.desktop_overlay_opacity !== null) return template.desktop_overlay_opacity;
    return template.overlay_opacity ?? 30;
  };

  const getOverlayStyle = () => {
    const baseOpacity = getOverlayOpacity();
    const direction = template.overlay_gradient_direction || 'to-b';
    const normalizeOpacity = (value: number | null | undefined, defaultValue: number) => {
      if (value === null || value === undefined) return defaultValue / 100;
      return value > 1 ? value / 100 : value;
    };
    const normalizedBaseOpacity = baseOpacity > 1 ? baseOpacity / 100 : baseOpacity;
    const fromOpacity = normalizeOpacity(template.overlay_gradient_from_opacity, 30) * normalizedBaseOpacity;
    const viaOpacity = normalizeOpacity(template.overlay_gradient_via_opacity, 25) * normalizedBaseOpacity;
    const toOpacity = normalizeOpacity(template.overlay_gradient_to_opacity, 40) * normalizedBaseOpacity;

    const directionMap: Record<string, string> = {
      'to-t': 'to top', 'to-b': 'to bottom', 'to-l': 'to left', 'to-r': 'to right',
      'to-tl': 'to top left', 'to-tr': 'to top right', 'to-bl': 'to bottom left', 'to-br': 'to bottom right'
    };
    const cssDirection = directionMap[direction] || 'to bottom';
    const colorMap: Record<string, string> = {
      'black': '0, 0, 0', 'white': '255, 255, 255', 'background': '0, 0, 0',
      'foreground': '255, 255, 255', 'primary': '1, 100, 80', 'secondary': '240, 240, 240'
    };
    const fromColor = colorMap[template.overlay_gradient_from || 'black'] || '0, 0, 0';
    const viaColor = colorMap[template.overlay_gradient_via || 'black'] || '0, 0, 0';
    const toColor = colorMap[template.overlay_gradient_to || 'black'] || '0, 0, 0';
    return { background: `linear-gradient(${cssDirection}, rgba(${fromColor}, ${fromOpacity}), rgba(${viaColor}, ${viaOpacity}), rgba(${toColor}, ${toOpacity}))` };
  };

  const mobileImg = template.mobile_image_url || sushiRamenMobile;
  const tabletImg = template.tablet_image_url || template.desktop_image_url || sushiRamenHero;
  const desktopImg = template.desktop_image_url || sushiRamenHero;
  const blurAmount = template.background_blur || 0;

  const desktopMediaType = (template as any).desktop_media_type || template.media_type || 'image';
  const tabletMediaType = (template as any).tablet_media_type || template.media_type || 'image';
  const mobileMediaType = (template as any).mobile_media_type || template.media_type || 'image';

  const isDesktopVideo = desktopMediaType === 'video' && !isLightweight;
  const isTabletVideo = tabletMediaType === 'video' && !isLightweight;
  const isMobileVideo = mobileMediaType === 'video' && !isLightweight;

  const mobileVideo = isMobileVideo ? template.mobile_video_url : null;
  const tabletVideo = isTabletVideo ? (template.tablet_video_url || template.desktop_video_url) : null;
  const desktopVideo = isDesktopVideo ? template.desktop_video_url : null;

  useEffect(() => {
    const deviceType = getDeviceType();
    const currentImage = deviceType === 'mobile' ? mobileImg : deviceType === 'tablet' ? tabletImg : desktopImg;
    if (currentImage) {
      const img = new Image();
      const handleReady = () => {
        setPostersLoaded(prev => ({ ...prev, [deviceType]: true }));
        setImagesLoaded(prev => ({ ...prev, [deviceType]: true }));
        if (isActive) {
          onContentReady?.();
          setTimeout(() => setShouldLoadVideo(true), 100);
        }
      };
      img.onload = handleReady;
      img.onerror = () => { console.warn('[HeroSlide] Image failed:', currentImage); handleReady(); };
      img.src = currentImage;
    } else if (isActive) {
      onContentReady?.();
    }
  }, [mobileImg, tabletImg, desktopImg, isActive, onContentReady]);

  useEffect(() => {
    if (isActive && postersLoaded[getDeviceType()]) setShouldLoadVideo(true);
  }, [isActive, postersLoaded]);

  const handleVideoCanPlay = (device: string) => setVideosReady(prev => ({ ...prev, [device]: true }));
  const handleVideoError = (device: string, error: any) => {
    console.error(`[HeroSlide] Video error on ${device}:`, error);
    setVideoErrors(prev => ({ ...prev, [device]: true }));
  };

  useEffect(() => {
    if (!shouldLoadVideo || !isActive) return;
    let isIOS = false;
    try { isIOS = isIOSDevice(); } catch {}
    if (!isIOS) return;
    const deviceType = getDeviceType();
    const videoRef = deviceType === 'mobile' ? mobileVideoRef : deviceType === 'tablet' ? tabletVideoRef : desktopVideoRef;
    const video = videoRef.current;
    if (!video) return;
    const attemptPlay = async () => {
      try {
        video.muted = true; video.playsInline = true;
        video.setAttribute('webkit-playsinline', 'true');
        await video.play();
      } catch (err) {
        setVideoErrors(prev => ({ ...prev, [deviceType]: true }));
      }
    };
    const timer = setTimeout(attemptPlay, 150);
    return () => clearTimeout(timer);
  }, [shouldLoadVideo, isActive]);

  const renderVideo = (device: string, videoUrl: string | null, isVideo: boolean, imgSrc: string, videoRef: React.RefObject<HTMLVideoElement>) => {
    if (isVideo && videoUrl) {
      return (
        <>
          <img src={imgSrc} alt="Background"
            className={cn("absolute inset-0 w-full h-full object-cover object-center z-10 transition-opacity duration-500",
              videosReady[device] && !videoErrors[device] ? "opacity-0 pointer-events-none" : "opacity-100"
            )}
            style={{ filter: blurAmount > 0 ? `blur(${blurAmount}px)` : undefined }}
          />
          {shouldLoadVideo && !videoErrors[device] && (
            <video ref={videoRef as any} src={videoUrl} autoPlay loop muted playsInline
              // @ts-ignore
              webkit-playsinline="true" preload="auto"
              onCanPlay={() => handleVideoCanPlay(device)}
              onError={(e) => handleVideoError(device, e)}
              className="absolute inset-0 w-full h-full object-cover object-center"
              style={{ filter: blurAmount > 0 ? `blur(${blurAmount}px)` : undefined }}
            />
          )}
        </>
      );
    }
    return (
      <img src={imgSrc} alt="Background"
        fetchPriority={device === 'desktop' ? 'high' : undefined}
        loading="eager" decoding="async"
        className={cn("absolute inset-0 w-full h-full object-cover object-center transition-opacity duration-500",
          imagesLoaded[device] ? "opacity-100" : "opacity-0"
        )}
        style={{ filter: blurAmount > 0 ? `blur(${blurAmount}px)` : undefined }}
      />
    );
  };

  return (
    <div className={cn("absolute inset-0 w-full h-full transition-opacity duration-1000", isActive ? "opacity-100 z-10" : "opacity-0 z-0")}>
      <div className="absolute inset-0 w-full h-full">
        {/* Mobile */}
        <div className="absolute inset-0 w-full h-full sm:hidden">
          {!imagesLoaded.mobile && <div className="absolute inset-0 w-full h-full bg-muted animate-pulse z-20" />}
          {renderVideo('mobile', mobileVideo, isMobileVideo, mobileImg, mobileVideoRef)}
        </div>
        {/* Tablet */}
        <div className="absolute inset-0 w-full h-full hidden sm:block lg:hidden">
          {!imagesLoaded.tablet && <div className="absolute inset-0 w-full h-full bg-muted animate-pulse z-20" />}
          {renderVideo('tablet', tabletVideo, isTabletVideo, tabletImg, tabletVideoRef)}
        </div>
        {/* Desktop */}
        <div className="absolute inset-0 w-full h-full hidden lg:block">
          {!imagesLoaded.desktop && <div className="absolute inset-0 w-full h-full bg-muted animate-pulse z-20" />}
          {renderVideo('desktop', desktopVideo, isDesktopVideo, desktopImg, desktopVideoRef)}
        </div>
        <div className="absolute inset-0 w-full h-full" style={getOverlayStyle()} />
      </div>

      {/* Content */}
      <div className="relative z-10 container mx-auto px-4 sm:px-6 flex items-center justify-center min-h-screen">
        <div className="max-w-4xl mx-auto text-center space-y-4 sm:space-y-8 animate-fade-in w-full">
          {template.target_country && (
            <p className="flex items-center justify-center gap-2 text-base sm:text-lg md:text-xl text-white/80 font-medium tracking-widest uppercase drop-shadow-[0_2px_6px_rgba(0,0,0,0.7)]">
              {countryFlagCodes[template.target_country] && (
                <img
                  src={`https://flagcdn.com/w40/${countryFlagCodes[template.target_country]}.png`}
                  alt={template.target_country}
                  width={28}
                  height={21}
                  className="inline-block rounded-sm shadow-sm"
                  loading="eager"
                />
              )}
              {t(`countries.${template.target_country}`, template.target_country)}
            </p>
          )}
          <h1 className="text-3xl sm:text-5xl md:text-7xl font-bold text-white leading-tight px-4 drop-shadow-[0_2px_8px_rgba(0,0,0,0.8)]">
            {getLocalizedText("title") || t("home.hero.title")}
          </h1>
          <p className="text-sm sm:text-xl md:text-2xl text-white/95 max-w-2xl mx-auto px-4 drop-shadow-[0_2px_6px_rgba(0,0,0,0.7)]">
            {getLocalizedText("description") || t("home.hero.description")}
          </p>
          {template.subtitle_button_text_zh && (
            <div className="flex flex-col items-center gap-3">
              <button onClick={onAskXiaoxiong}
                className="group flex items-center gap-3 bg-white/20 backdrop-blur-xl text-white px-5 sm:px-7 py-3.5 sm:py-4 rounded-full shadow-[0_8px_32px_rgba(0,0,0,0.12)] hover:shadow-[0_16px_48px_rgba(0,0,0,0.2)] hover:bg-white/30 transition-all duration-300 cursor-text border border-white/40">
                <MessageCircle className="w-5 h-5 text-white/90 group-hover:text-white transition-colors drop-shadow-sm" />
                <span className="text-sm sm:text-base text-white group-hover:text-white/80 transition-colors drop-shadow-sm font-medium">
                  {getLocalizedText("subtitle_button_text") || t("home.hero.subtitle")}
                </span>
                <Search className="w-4 h-4 text-white/60 ml-2 drop-shadow-sm" />
              </button>
              <div className="flex items-center gap-3 w-64">
                <div className="flex-1 h-px bg-white/30" />
                <span className="text-xs text-white/60">{t("aiRecipe.or", "或者")}</span>
                <div className="flex-1 h-px bg-white/30" />
              </div>
              <button onClick={onDIYCook}
                className="group flex items-center gap-3 bg-white/20 backdrop-blur-xl text-white px-5 sm:px-7 py-3.5 sm:py-4 rounded-full shadow-[0_8px_32px_rgba(0,0,0,0.12)] hover:shadow-[0_16px_48px_rgba(0,0,0,0.2)] hover:bg-white/30 transition-all duration-300 border border-white/40">
                <ChefHat className="w-5 h-5 text-white/90 group-hover:text-white transition-colors drop-shadow-sm" />
                <span className="text-sm sm:text-base text-white group-hover:text-white/80 transition-colors drop-shadow-sm font-medium">
                  {t("aiRecipe.diyCook", "自己动手做")}
                </span>
                <BookOpen className="w-4 h-4 text-white/70 group-hover:text-white/90 transition-colors drop-shadow-sm" />
              </button>
            </div>
          )}
        </div>
      </div>

      {/* Photo Story Point */}
      {(() => {
        const storyText = getLocalizedText("photo_story") || t("home.hero.photoStoryContent");
        if (!storyText) return null;
        return (
          <button onClick={() => onPhotoStory?.(storyText, template.id, (template as any).restaurant_id)}
            className="absolute bottom-36 left-8 z-20 group flex items-center gap-2 cursor-pointer"
            aria-label={t("home.hero.photoStory")}>
            <div className="flex items-center gap-2">
              <span className="relative flex h-4 w-4 shrink-0">
                <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-white/70 opacity-75" />
                <span className="relative inline-flex rounded-full h-4 w-4 bg-white shadow-lg" />
              </span>
              <span className="text-xs text-white/80 max-w-0 group-hover:max-w-[200px] overflow-hidden transition-all duration-500 ease-out drop-shadow-md whitespace-nowrap">
                {t("home.hero.photoStory")}
              </span>
              <HeroReactionCounts templateId={template.id} />
            </div>
          </button>
        );
      })()}

      {/* Claim Store Button */}
      <button onClick={onClaimStore}
        className="absolute bottom-20 left-8 z-20 group flex items-center gap-2 bg-primary hover:bg-primary/90 backdrop-blur-md px-5 py-2.5 rounded-full shadow-[0_4px_20px_rgba(0,0,0,0.25)] hover:shadow-[0_6px_28px_rgba(0,0,0,0.35)] transition-all duration-300 cursor-pointer"
        aria-label={t("home.hero.claimStore")}>
        <Store className="w-4 h-4 text-primary-foreground drop-shadow-sm" />
        <span className="text-xs sm:text-sm text-primary-foreground font-semibold drop-shadow-md">
          {t("home.hero.claimStore")}
        </span>
      </button>
    </div>
  );
});
HeroSlide.displayName = "HeroSlide";

export default HeroSlide;
export { HeroReactionCounts };
