import { useState } from "react";
import { useTranslation } from "react-i18next";
import { useNavigate } from "react-router-dom";
import { Camera, ThumbsUp, ThumbsDown, Share2, MessageSquare, Loader2, RotateCcw, Languages, Store } from "lucide-react";
import { Button } from "@/components/ui/button";
import { toast } from "sonner";
import { useStoryReactions } from "@/hooks/useStoryReactions";
import { useAuth } from "@/contexts/AuthContext";
import { useComments } from "@/hooks/useComments";
import RestaurantComments from "@/components/RestaurantComments";
import IChingSection, { useStoryTranslation } from "@/components/IChingSection";
import DislikeReasonDialog from "@/components/DislikeReasonDialog";

const PhotoStoryDialog = ({ content, onClose, templateId, restaurantId }: { content: string; onClose: () => void; templateId?: string; restaurantId?: string | null }) => {
  const { t, i18n } = useTranslation();
  const navigate = useNavigate();
  const iChingText = t("home.hero.photoStoryIChing", '《易经·井》：\u201C井养而不穷也。\u201D —— 一口井滋养着周围的人，从不枯竭。这个街角的拉面店正如一口古井，日复一日为邻里提供温暖与慰藉，维系着社区最朴素的纽带。');
  const { narrativeDisplay, iChingDisplay, translateStory, isTranslating, showTranslation } = useStoryTranslation(content, iChingText);
  const { counts, userReaction, toggleReaction } = useStoryReactions(templateId, "template");
  const { user } = useAuth();
  const [showComments, setShowComments] = useState(false);
  const [showDislikeDialog, setShowDislikeDialog] = useState(false);
  const { data: storyComments } = useComments(templateId || "", "story", { enabled: !!templateId });
  const commentsCount = storyComments?.reduce((acc: number, c: any) => acc + 1 + (c.replies?.length || 0), 0) || 0;

  const handleShare = async () => {
    try {
      if (navigator.share) {
        await navigator.share({ title: t("home.hero.photoStory"), url: window.location.href });
      } else {
        await navigator.clipboard.writeText(window.location.href);
        toast.success(t("common.linkCopied", "链接已复制"));
      }
    } catch { /* cancelled */ }
  };

  return (
    <>
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/70" onClick={onClose}>
      <div className="relative max-w-lg w-full mx-4 bg-background rounded-2xl shadow-2xl overflow-hidden animate-fade-in"
        onClick={(e) => e.stopPropagation()}>
        <div className="p-6 sm:p-8 space-y-4">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-full bg-primary/10 flex items-center justify-center">
              <Camera className="w-5 h-5 text-primary" />
            </div>
            <h3 className="text-lg font-bold text-foreground">{t("home.hero.photoStory")}</h3>
          </div>
          <p className="text-sm sm:text-base text-muted-foreground leading-relaxed">
            {narrativeDisplay || content}
          </p>
          <div className="pt-3 border-t border-border/50">
            <IChingSection text={iChingText} translatedText={iChingDisplay} />
          </div>
          {/* Like / Dislike / Share / Comments */}
          <div className="flex items-center justify-center gap-4 pt-2 border-t border-border/50">
            <button onClick={() => toggleReaction.mutate({ type: "like" })}
              className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-sm font-medium transition-all duration-200 active:scale-95 ${
                userReaction === "like" ? "bg-primary/15 text-primary" : "text-muted-foreground hover:text-primary hover:bg-primary/10"
              }`}>
              <ThumbsUp className={`w-4 h-4 ${userReaction === "like" ? "fill-primary" : ""}`} />
              {counts.likes > 0 && <span>{counts.likes}</span>}
            </button>
            <button onClick={() => {
              if (userReaction !== "dislike") { setShowDislikeDialog(true); return; }
              toggleReaction.mutate({ type: "dislike" });
            }}
              className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-sm font-medium transition-all duration-200 active:scale-95 ${
                userReaction === "dislike" ? "bg-destructive/15 text-destructive" : "text-muted-foreground hover:text-destructive hover:bg-destructive/10"
              }`}>
              <ThumbsDown className={`w-4 h-4 ${userReaction === "dislike" ? "fill-destructive" : ""}`} />
              {counts.dislikes > 0 && <span>{counts.dislikes}</span>}
            </button>
            <button onClick={handleShare}
              className="inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-sm font-medium text-muted-foreground hover:text-primary hover:bg-primary/10 transition-all duration-200 active:scale-95">
              <Share2 className="w-4 h-4" />
            </button>
            <button onClick={() => setShowComments(!showComments)}
              className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-sm font-medium transition-all duration-200 active:scale-95 ${
                showComments ? "bg-primary/15 text-primary" : "text-muted-foreground hover:text-primary hover:bg-primary/10"
              }`}>
              <MessageSquare className="w-4 h-4" />
              {commentsCount > 0 && <span>{commentsCount}</span>}
            </button>
          </div>
          {showComments && templateId && (
            <div className="mt-2">
              <RestaurantComments targetId={templateId} targetType="story" />
            </div>
          )}
          {/* Visit Store Button */}
          {restaurantId && (
            <div className="pt-1">
              <Button
                variant="outline"
                size="sm"
                className="w-full gap-2 rounded-full border-primary/30 text-primary hover:bg-primary/10 hover:border-primary/50"
                onClick={() => {
                  onClose();
                  navigate(`/restaurant/${restaurantId}`);
                }}
              >
                <Store className="w-4 h-4" />
                {t("home.hero.visitStore", "进入商店")}
              </Button>
            </div>
          )}
          <div className="flex items-center justify-between">
            {i18n.language !== "zh" ? (
              <Button variant="outline" size="sm"
                className="gap-2 h-auto py-2 px-4 text-sm font-medium border-primary/30 text-primary hover:bg-primary/10 hover:border-primary/50 rounded-full transition-all duration-300"
                onClick={() => translateStory(i18n.language)} disabled={isTranslating}>
                {isTranslating ? (
                  <><Loader2 className="h-3.5 w-3.5 animate-spin" /><span>{t("translate.translating", "翻译中...")}</span></>
                ) : showTranslation ? (
                  <><RotateCcw className="h-3.5 w-3.5" /><span>{t("translate.showOriginal", "显示原文")}</span></>
                ) : (
                  <><Languages className="h-3.5 w-3.5" /><span>{t("translate.button", "翻译")}</span></>
                )}
              </Button>
            ) : <div />}
            <button onClick={onClose} className="text-sm text-primary hover:text-primary/80 transition-colors">
              {t("common.close", "关闭")}
            </button>
          </div>
        </div>
      </div>
    </div>
    <DislikeReasonDialog
      open={showDislikeDialog}
      onOpenChange={setShowDislikeDialog}
      onSubmit={(reason) => toggleReaction.mutate({ type: "dislike", reason })}
    />
    </>
  );
};

export default PhotoStoryDialog;
